#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e6+5;
LL n,Q,B,a[N];
LL L[N],R[N],bel[N];
LL p[N],tag[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void change(int l,int r,LL k){
    int ll=bel[l],rr=bel[r];
    if(ll==rr){//没有整块
        for(int i=l;i<=r;i++)a[i]+=k;
        for(int i=L[ll];i<=R[rr];i++)p[i]=a[i];
        sort(p+L[ll],p+R[rr]+1);
    }else{
        for(int i=ll+1;i<rr;i++)tag[i]+=k;//懒标记
        for(int i=l;i<=R[ll];i++)a[i]+=k;
        for(int i=L[ll];i<=R[ll];i++)p[i]=a[i];
        sort(p+L[ll],p+R[ll]+1);
        for(int i=L[rr];i<=r;i++)a[i]+=k;
        for(int i=L[rr];i<=R[rr];i++)p[i]=a[i];
        sort(p+L[rr],p+R[rr]+1);
    }return;
}
LL query(int l,int r,LL k){
    int ll=bel[l],rr=bel[r];
    if(ll==rr){//属于同一块，直接暴力
        LL ans=0;
        for(int i=l;i<=r;i++)
            if(a[i]+tag[ll]>=k)ans++;
        return ans;
    }else{
        LL ans=0;
        for(int i=ll+1;i<rr;i++){
            int pos=lower_bound(p+L[i],p+R[i]+1,k-tag[i])-p;
            ans+=R[i]-pos+1;
        }//整块的处理：二分
        for(int i=l;i<=R[ll];i++)
            if(a[i]+tag[ll]>=k)ans++;
        for(int i=L[rr];i<=r;i++)
            if(a[i]+tag[rr]>=k)ans++;
        return ans;
    }
}
int main(){
    n=read(),Q=read();B=sqrt(n);
    for(int i=1;i<=n;i++)
        a[i]=read(),p[i]=a[i];
    for(int i=1;i<=B;i++)
        L[i]=R[i-1]+1,R[i]=R[i-1]+B;
    if(R[B]<n)++B,L[B]=R[B-1]+1,R[B]=n;
    for(int i=1;i<=B;i++){
        for(int x=L[i];x<=R[i];x++)bel[x]=i;
        sort(p+L[i],p+R[i]+1);
    }
    while(Q--){
        char opt;cin>>opt;
        LL l=read(),r=read(),k=read();
        if(opt=='M')change(l,r,k);
        else cout<<query(l,r,k)<<"\n";
    }
    return 0;
}
